1	<!DOCTYPE HTML>
2	<html lang="en">
3	<head>
4	  <meta charset="UTF-8">
5	  <title>PathFinding.js — Scenario Builder</title>
6	  <link rel="stylesheet" href="./css/style.css">
7	  <link rel="stylesheet" href="./lib/themes/jquery.ui.all.css">
8	  <style>
9	    /* ── Scenario builder layout ───────────────────────────────── */
10	    body { margin: 0; padding: 0; font-family: Arial, sans-serif; background: #1a1a2e; color: #eee; }
11	
12	    #draw_area { display: block; }
13	
14	    #scenario_panel {
15	      position: fixed;
16	      top: 10px;
17	      right: 10px;
18	      width: 240px;
19	      background: #16213e;
20	      border: 1px solid #0f3460;
21	      border-radius: 6px;
22	      padding: 12px;
23	      z-index: 100;
24	      box-shadow: 0 4px 16px rgba(0,0,0,0.5);
25	    }
26	
27	    #scenario_panel h2 {
28	      margin: 0 0 12px 0;
29	      font-size: 14px;
30	      color: #e94560;
31	      text-transform: uppercase;
32	      letter-spacing: 1px;
33	    }
34	
35	    .ctrl-group { margin-bottom: 12px; }
36	    .ctrl-group label {
37	      display: block;
38	      font-size: 11px;
39	      color: #aaa;
40	      margin-bottom: 4px;
41	      text-transform: uppercase;
42	      letter-spacing: 0.5px;
43	    }
44	
45	    .ctrl-group select,
46	    .ctrl-group input[type=number] {
47	      width: 100%;
48	      box-sizing: border-box;
49	      background: #0f3460;
50	      color: #eee;
51	      border: 1px solid #1a4a7a;
52	      border-radius: 4px;
53	      padding: 5px 8px;
54	      font-size: 12px;
55	    }
56	
57	    .ctrl-group input[type=range] {
58	      width: 100%;
59	      box-sizing: border-box;
60	      accent-color: #e94560;
61	    }
62	
63	    .speed-value { font-size: 11px; color: #aaa; text-align: right; }
64	
65	    .grid-size-row { display: flex; gap: 6px; align-items: center; }
66	    .grid-size-row input { flex: 1; }
67	    .grid-size-row span { color: #aaa; font-size: 12px; }
68	
69	    .btn-row { display: flex; gap: 6px; }
70	    .btn-row .btn { flex: 1; }
71	
72	    .btn {
73	      display: block;
74	      width: 100%;
75	      padding: 7px 0;
76	      background: #0f3460;
77	      color: #eee;
78	      border: 1px solid #1a4a7a;
79	      border-radius: 4px;
80	      font-size: 12px;
81	      cursor: pointer;
82	      text-align: center;
83	      transition: background 0.15s;
84	    }
85	    .btn:hover { background: #1a4a7a; }
86	    .btn.primary { background: #e94560; border-color: #e94560; font-weight: bold; }
87	    .btn.primary:hover { background: #c73652; }
88	    .btn.danger { background: #553; border-color: #776; }
89	    .btn.danger:hover { background: #776; }
90	
91	    #status_bar {
92	      position: fixed;
93	      bottom: 10px;
94	      left: 50%;
95	      transform: translateX(-50%);
96	      background: rgba(22,33,62,0.9);
97	      border: 1px solid #0f3460;
98	      border-radius: 4px;
99	      padding: 6px 16px;
100	      font-size: 12px;
101	      color: #aaa;
102	      pointer-events: none;
103	    }
104	
105	    /* ── Score card ────────────────────────────────────────────── */
106	    #score_card {
107	      display: none;
108	      position: fixed;
109	      bottom: 40px;
110	      left: 10px;
111	      width: 220px;
112	      background: #16213e;
113	      border: 1px solid #0f3460;
114	      border-radius: 6px;
115	      padding: 12px;
116	      z-index: 200;
117	      box-shadow: 0 4px 16px rgba(0,0,0,0.5);
118	      font-size: 12px;
119	    }
120	    #score_card h3 {
121	      margin: 0 0 8px 0;
122	      font-size: 13px;
123	      color: #e94560;
124	      text-transform: uppercase;
125	      letter-spacing: 1px;
126	    }
127	    .sc-row { display: flex; justify-content: space-between; margin-bottom: 4px; }
128	    .sc-label { color: #aaa; }
129	    .sc-val { color: #eee; font-weight: bold; }
130	    .sc-saved-msg { display: none; color: #4caf50; font-size: 11px; margin-top: 4px; }
131	    #score_card .sc-close {
132	      position: absolute; top: 6px; right: 8px;
133	      background: none; border: none; color: #aaa; cursor: pointer; font-size: 14px;
134	    }
135	
136	    /* ── Comparison drawer ─────────────────────────────────────── */
137	    #comparison_drawer {
138	      display: none;
139	      position: fixed;
140	      top: 10px;
141	      left: 10px;
142	      max-width: calc(100vw - 280px);
143	      background: #16213e;
144	      border: 1px solid #0f3460;
145	      border-radius: 6px;
146	      padding: 12px;
147	      z-index: 200;
148	      box-shadow: 0 4px 16px rgba(0,0,0,0.5);
149	      overflow-x: auto;
150	    }
151	    #comparison_drawer h3 {
152	      margin: 0 0 8px 0;
153	      font-size: 13px;
154	      color: #e94560;
155	      text-transform: uppercase;
156	      letter-spacing: 1px;
157	    }
158	    #comparison_drawer table {
159	      border-collapse: collapse;
160	      font-size: 12px;
161	      width: 100%;
162	    }
163	    #comparison_drawer th {
164	      color: #aaa;
165	      text-align: left;
166	      padding: 4px 8px;
167	      border-bottom: 1px solid #0f3460;
168	    }
169	    #comparison_drawer td { padding: 4px 8px; color: #eee; }
170	    #comparison_drawer tr:hover td { background: rgba(15,52,96,0.4); }
171	    .del-run-btn {
172	      background: none; border: none; color: #e94560; cursor: pointer; font-size: 12px;
173	    }
174	  </style>
175	</head>
176	<body>
177	
178	<div id="draw_area"></div>
179	
180	<div id="scenario_panel">
181	  <h2>Scenario Builder</h2>
182	
183	  <!-- Algorithm selector -->
184	  <div class="ctrl-group">
185	    <label for="algo_select">Algorithm</label>
186	    <select id="algo_select"></select>
187	  </div>
188	
189	  <!-- Preset map selector -->
190	  <div class="ctrl-group">
191	    <label for="preset_select">Preset Map</label>
192	    <select id="preset_select">
193	      <option value="">— choose preset —</option>
194	    </select>
195	  </div>
196	
197	  <!-- Grid size -->
198	  <div class="ctrl-group">
199	    <label>Grid Size</label>
200	    <div class="grid-size-row">
201	      <input type="number" id="grid_width"  min="5" max="50" value="15">
202	      <span>×</span>
203	      <input type="number" id="grid_height" min="5" max="50" value="15">
204	    </div>
205	  </div>
206	
207	  <!-- Speed slider -->
208	  <div class="ctrl-group">
209	    <label>Animation Speed — <span id="speed_label">200 ops/s</span></label>
210	    <input type="range" id="speed_slider" min="10" max="1000" value="200" step="10">
211	  </div>
212	
213	  <!-- Primary action buttons -->
214	  <div class="ctrl-group">
215	    <button class="btn primary" id="btn_find_path">Find Path</button>
216	  </div>
217	
218	  <div class="ctrl-group btn-row">
219	    <button class="btn danger" id="btn_clear">Clear</button>
220	    <button class="btn" id="btn_apply_size">Resize Grid</button>
221	  </div>
222	
223	  <!-- Save / Load -->
224	  <div class="ctrl-group btn-row">
225	    <button class="btn" id="btn_save">Save Scenario</button>
226	    <button class="btn" id="btn_load">Load Scenario</button>
227	  </div>
228	
229	  <!-- Comparison -->
230	  <div class="ctrl-group">
231	    <button class="btn" id="show_comparison">Compare Runs</button>
232	  </div>
233	
234	  <!-- Hidden file input for load -->
235	  <input type="file" id="file_input" accept=".json" style="display:none">
236	</div>
237	
238	<!-- Score card -->
239	<div id="score_card" style="display:none;position:fixed;bottom:50px;left:50%;transform:translateX(-50%);
240	  background:#16213e;border:1px solid #0f3460;border-radius:6px;padding:14px 18px;
241	  z-index:200;box-shadow:0 4px 16px rgba(0,0,0,0.6);min-width:280px;font-size:13px;">
242	  <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;">
243	    <strong style="color:#e94560;">Results</strong>
244	    <button class="sc-close" style="background:none;border:none;color:#aaa;cursor:pointer;font-size:16px;">✕</button>
245	  </div>
246	  <table style="width:100%;border-collapse:collapse;">
247	    <tr><td style="color:#aaa;padding:3px 0;">Algorithm</td><td class="sc-algorithm" style="text-align:right;font-weight:bold;"></td></tr>
248	    <tr><td style="color:#aaa;padding:3px 0;">Path length</td><td class="sc-path-length" style="text-align:right;"></td></tr>
249	    <tr><td style="color:#aaa;padding:3px 0;">Nodes explored</td><td class="sc-nodes" style="text-align:right;"></td></tr>
250	    <tr><td style="color:#aaa;padding:3px 0;">Time</td><td class="sc-time" style="text-align:right;"></td></tr>
251	  </table>
252	  <div style="margin-top:10px;display:flex;align-items:center;gap:8px;">
253	    <button class="btn sc-save-btn" style="width:auto;padding:5px 14px;">Save Run</button>
254	    <span class="sc-saved-msg" style="display:none;color:#4caf50;font-size:11px;"></span>
255	  </div>
256	</div>
257	
258	<!-- Comparison drawer -->
259	<div id="comparison_drawer" style="display:none;position:fixed;bottom:0;left:0;right:0;
260	  background:#16213e;border-top:2px solid #0f3460;z-index:300;max-height:260px;overflow-y:auto;padding:12px;">
261	  <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">
262	    <strong style="color:#e94560;font-size:13px;">Saved Runs</strong>
263	    <button id="clear_runs_btn" class="btn danger" style="width:auto;padding:4px 12px;font-size:11px;">Clear All</button>
264	  </div>
265	  <table style="width:100%;border-collapse:collapse;font-size:12px;">
266	    <thead>
267	      <tr style="color:#aaa;text-align:left;">
268	        <th style="padding:4px 8px;">Time</th>
269	        <th style="padding:4px 8px;">Algorithm</th>
270	        <th style="padding:4px 8px;">Path Len</th>
271	        <th style="padding:4px 8px;">Nodes</th>
272	        <th style="padding:4px 8px;">Duration</th>
273	        <th style="padding:4px 8px;"></th>
274	      </tr>
275	    </thead>
276	    <tbody></tbody>
277	  </table>
278	</div>
279	
280	<div id="status_bar">Draw walls · Drag start (green) and end (red) nodes</div>
281	
282	<!-- Dependencies -->
283	<script src="./lib/raphael-min.js"></script>
284	<script src="./lib/es5-shim.min.js"></script>
285	<script src="./lib/jquery-1.7.2.min.js"></script>
286	<script src="./lib/state-machine.min.js"></script>
287	<script src="./lib/async.min.js"></script>
288	
289	<script src="./lib/ui/jquery.ui.core.min.js"></script>
290	<script src="./lib/ui/jquery.ui.widget.min.js"></script>
291	<script src="./lib/ui/jquery.ui.mouse.min.js"></script>
292	<script src="./lib/ui/jquery.ui.draggable.min.js"></script>
293	
294	<script src="./lib/pathfinding-browser.min.js"></script>
295	
296	<script src="./js/view.js"></script>
297	<script src="./js/scenario-controls.js"></script>
298	<script src="./js/scorer.js"></script>
299	<script>
300	/**
301	 * Scenario Builder — wires ScenarioControls config to View + PF.
302	 * Minimal controller; leans on existing View for rendering.
303	 */
304	(function() {
305	    var SC     = ScenarioControls;
306	    var grid   = null;
307	    var startX = 1, startY = 1, endX = 13, endY = 13;
308	    var opsPerSecond = SC.SPEED_CONFIG.default;
309	    var isSearching  = false;
310	    var operations   = [];
311	    var animTimer    = null;
312	
313	    // ── Populate algorithm dropdown ────────────────────────────────────────
314	    var $algoSelect = $('#algo_select');
315	    SC.ALGORITHMS.forEach(function(algo) {
316	        $('<option>').val(algo.id).text(algo.label).appendTo($algoSelect);
317	    });
318	
319	    // ── Populate preset dropdown ───────────────────────────────────────────
320	    var $presetSelect = $('#preset_select');
321	    SC.PRESETS.forEach(function(preset) {
322	        $('<option>').val(preset.id).text(preset.label).appendTo($presetSelect);
323	    });
324	
325	    // ── Speed slider ───────────────────────────────────────────────────────
326	    $('#speed_slider').on('input change', function() {
327	        opsPerSecond = parseInt(this.value);
328	        $('#speed_label').text(opsPerSecond + ' ops/s');
329	    });
330	
331	    // ── Grid init ─────────────────────────────────────────────────────────
332	    function initGrid(w, h, sx, sy, ex, ey) {
333	        w  = w  || SC.GRID_SIZE_DEFAULT.width;
334	        h  = h  || SC.GRID_SIZE_DEFAULT.height;
335	        sx = (sx !== undefined) ? sx : 1;
336	        sy = (sy !== undefined) ? sy : Math.floor(h / 2);
337	        ex = (ex !== undefined) ? ex : w - 2;
338	        ey = (ey !== undefined) ? ey : Math.floor(h / 2);
339	
340	        if (!SC.validateGridSize(w, h)) {
341	            setStatus('Invalid grid size: must be 5–50.');
342	            return;
343	        }
344	
345	        startX = sx; startY = sy; endX = ex; endY = ey;
346	        grid = new PF.Grid(w, h);
347	        abortSearch();
348	
349	        View.init({ numCols: w, numRows: h });
350	        View.generateGrid(function() {
351	            View.setStartPos(startX, startY);
352	            View.setEndPos(endX, endY);
353	            bindDrawEvents();
354	        });
355	    }
356	
357	    // ── Draw events (wall drawing / dragging start+end) ────────────────────
358	    function bindDrawEvents() {
359	        var drawing = null; // 'wall' | 'erase' | 'dragStart' | 'dragEnd'
360	
361	        $('#draw_area').off('mousedown').on('mousedown', function(e) {
362	            if (isSearching) return;
363	            var coord = View.toGridCoordinate(e.pageX, e.pageY);
364	            var gx = coord[0], gy = coord[1];
365	
366	            if (gx === startX && gy === startY) { drawing = 'dragStart'; return; }
367	            if (gx === endX   && gy === endY)   { drawing = 'dragEnd';   return; }
368	
369	            if (grid.isWalkableAt(gx, gy)) {
370	                drawing = 'wall';
371	                setWalkable(gx, gy, false);
372	            } else {
373	                drawing = 'erase';
374	                setWalkable(gx, gy, true);
375	            }
376	        });
377	
378	        $(window).off('mousemove.sb').on('mousemove.sb', function(e) {
379	            if (!drawing) return;
380	            var coord = View.toGridCoordinate(e.pageX, e.pageY);
381	            var gx = coord[0], gy = coord[1];
382	            if (gx < 0 || gy < 0 || gx >= grid.width || gy >= grid.height) return;
383	
384	            if (drawing === 'dragStart' && grid.isWalkableAt(gx, gy) &&
385	                !(gx === endX && gy === endY)) {
386	                startX = gx; startY = gy;
387	                View.setStartPos(gx, gy);
388	            } else if (drawing === 'dragEnd' && grid.isWalkableAt(gx, gy) &&
389	                       !(gx === startX && gy === startY)) {
390	                endX = gx; endY = gy;
391	                View.setEndPos(gx, gy);
392	            } else if (drawing === 'wall' && !(gx === startX && gy === startY) &&
393	                       !(gx === endX && gy === endY)) {
394	                setWalkable(gx, gy, false);
395	            } else if (drawing === 'erase') {
396	                setWalkable(gx, gy, true);
397	            }
398	        });
399	
400	        $(window).off('mouseup.sb').on('mouseup.sb', function() {
401	            drawing = null;
402	        });
403	    }
404	
405	    function setWalkable(gx, gy, walkable) {
406	        grid.setWalkableAt(gx, gy, walkable);
407	        View.setAttributeAt(gx, gy, 'walkable', walkable);
408	    }
409	
410	    // ── Find Path ─────────────────────────────────────────────────────────
411	    hookNodeTracking();
412	
413	    function hookNodeTracking() {
414	        PF.Node.prototype = {
415	            get opened() { return this._opened; },
416	            set opened(v) {
417	                this._opened = v;
418	                operations.push({ x: this.x, y: this.y, attr: 'opened', value: v });
419	            },
420	            get closed() { return this._closed; },
421	            set closed(v) {
422	                this._closed = v;
423	                operations.push({ x: this.x, y: this.y, attr: 'closed', value: v });
424	            },
425	            get tested() { return this._tested; },
426	            set tested(v) {
427	                this._tested = v;
428	                operations.push({ x: this.x, y: this.y, attr: 'tested', value: v });
429	            },
430	        };
431	    }
432	
433	    function findPath() {
434	        if (!grid) return;
435	        abortSearch();
436	        View.clearFootprints && View.clearFootprints();
437	        View.clearPath && View.clearPath();
438	        operations = [];
439	
440	        var algoId  = $('#algo_select').val();
441	        var finder  = buildFinder(algoId);
442	        if (!finder) { setStatus('Unknown algorithm: ' + algoId); return; }
443	
444	        var cloned  = grid.clone();
445	        var t0      = performance.now ? performance.now() : Date.now();
446	        var path    = finder.findPath(startX, startY, endX, endY, cloned);
447	        var timeMs  = (performance.now ? performance.now() : Date.now()) - t0;
448	        var opsCopy = operations.slice();
449	        operations  = [];
450	
451	        // Count unique nodes explored (opened or closed)
452	        var exploredSet = {};
453	        opsCopy.forEach(function(op) {
454	            if (op.attr === 'opened' || op.attr === 'closed') {
455	                exploredSet[op.x + ',' + op.y] = true;
456	            }
457	        });
458	        var nodesExplored = Object.keys(exploredSet).length;
459	
460	        isSearching = true;
461	        setStatus('Searching…');
462	
463	        var opIdx = 0;
464	        animTimer = setInterval(function() {
465	            if (opIdx >= opsCopy.length) {
466	                clearInterval(animTimer);
467	                isSearching = false;
468	                View.drawPath(path);
469	                if (path.length) {
470	                    setStatus('Path found · ' + path.length + ' nodes');
471	                } else {
472	                    setStatus('No path found');
473	                }
474	                // Show score card
475	                var algoLabel = (function() {
476	                    var sel = $('#algo_select option:selected');
477	                    return sel.length ? sel.text() : algoId;
478	                }());
479	                var record = Scorer.captureRun(algoLabel, path, timeMs, nodesExplored);
480	                Scorer.showScoreCard(record);
481	                return;
482	            }
483	            var op = opsCopy[opIdx++];
484	            if (View.supportedOperations.indexOf(op.attr) !== -1) {
485	                View.setAttributeAt(op.x, op.y, op.attr, op.value);
486	            }
487	        }, 1000 / opsPerSecond);
488	    }
489	
490	    function abortSearch() {
491	        if (animTimer) { clearInterval(animTimer); animTimer = null; }
492	        isSearching = false;
493	    }
494	
495	    function buildFinder(id) {
496	        switch (id) {
497	            case 'AStarFinder':          return new PF.AStarFinder();
498	            case 'BiAStarFinder':        return new PF.BiAStarFinder();
499	            case 'BestFirstFinder':      return new PF.BestFirstFinder();
500	            case 'BiBestFirstFinder':    return new PF.BiBestFirstFinder();
501	            case 'BreadthFirstFinder':   return new PF.BreadthFirstFinder();
502	            case 'BiBreadthFirstFinder': return new PF.BiBreadthFirstFinder();
503	            case 'DijkstraFinder':       return new PF.DijkstraFinder();
504	            case 'BiDijkstraFinder':     return new PF.BiDijkstraFinder();
505	            case 'IDAStarFinder':        return new PF.IDAStarFinder({ timeLimit: 10 });
506	            case 'JumpPointFinder':      return new PF.JumpPointFinder({
507	                diagonalMovement: PF.DiagonalMovement.IfAtMostOneObstacle
508	            });
509	            default: return null;
510	        }
511	    }
512	
513	    // ── Clear ─────────────────────────────────────────────────────────────
514	    function clearGrid() {
515	        if (!grid) return;
516	        abortSearch();
517	        var w = grid.width, h = grid.height;
518	        initGrid(w, h, startX, startY, endX, endY);
519	        setStatus('Grid cleared');
520	    }
521	
522	    // ── Resize ────────────────────────────────────────────────────────────
523	    function resizeGrid() {
524	        var w = parseInt($('#grid_width').val());
525	        var h = parseInt($('#grid_height').val());
526	        if (!SC.validateGridSize(w, h)) {
527	            setStatus('Invalid size: must be 5–50.');
528	            return;
529	        }
530	        initGrid(w, h);
531	    }
532	
533	    // ── Preset load ───────────────────────────────────────────────────────
534	    $('#preset_select').on('change', function() {
535	        var id = this.value;
536	        if (!id) return;
537	        var preset = SC.PRESETS.filter(function(p) { return p.id === id; })[0];
538	        if (!preset) return;
539	        loadScenario(preset.scenario);
540	        this.value = '';
541	        setStatus('Loaded preset: ' + preset.label);
542	    });
543	
544	    function loadScenario(data) {
545	        try {
546	            var restored = SC.deserializeGrid(data);
547	            var w = restored.grid.width, h = restored.grid.height;
548	            abortSearch();
549	            grid = restored.grid;
550	            startX = restored.startX; startY = restored.startY;
551	            endX   = restored.endX;   endY   = restored.endY;
552	
553	            $('#grid_width').val(w);
554	            $('#grid_height').val(h);
555	
556	            View.init({ numCols: w, numRows: h });
557	            View.generateGrid(function() {
558	                // Restore walls
559	                for (var y = 0; y < h; y++) {
560	                    for (var x = 0; x < w; x++) {
561	                        if (!grid.isWalkableAt(x, y)) {
562	                            View.setAttributeAt(x, y, 'walkable', false);
563	                        }
564	                    }
