578	        var data = SC.serializeGrid(grid, startX, startY, endX, endY);
579	        var json = JSON.stringify(data, null, 2);
580	        var blob = new Blob([json], { type: 'application/json' });
581	        var url  = URL.createObjectURL(blob);
582	        var a    = document.createElement('a');
