143	        });
144	
145	        // Hide score card
146	        $('#score_card .sc-close').on('click', function() {
147	            $('#score_card').hide();
148	        });
149	    }
150	
151	    return {
152	        init:         init,
153	        captureRun:   captureRun,
154	        showScoreCard: showScoreCard,
155	        refreshDrawer: refreshDrawer,
156	        loadRuns:     loadRuns,
157	        clearRuns:    clearRuns
158	    };
159	
