1	/**
2	 * GridCanvas — pure state model for an interactive pathfinding scenario builder.
3	 *
4	 * No DOM / Raphael dependency; safe to require in Node for testing.
5	 *
6	 * Cell types: 'empty' | 'wall' | 'start' | 'end'
7	 *
8	 * API:
9	 *   getCell(x, y)          → cell type string
10	 *   toggleWall(x, y)       → flip empty↔wall (noop on start/end)
11	 *   setStart(x, y)         → place/move start marker
12	 *   setEnd(x, y)           → place/move end marker
13	 *   isWalkable(x, y)       → true unless wall
14	 *   clearWalls()           → remove all walls, keep start/end
15	 *   reset()                → clear everything
16	 *   getState()             → { grid, start, end, walls } snapshot
17	 *   setState(state)        → restore from snapshot
18	 */
19	function GridCanvas(cols, rows) {
20	    this.cols = cols;
21	    this.rows = rows;
22	    this.start = null;
23	    this.end   = null;
24	    this._grid = this._makeGrid(cols, rows);
25	}
26	
27	GridCanvas.prototype._makeGrid = function(cols, rows) {
28	    var grid = new Array(rows);
29	    for (var r = 0; r < rows; r++) {
30	        grid[r] = new Array(cols);
31	        for (var c = 0; c < cols; c++) {
32	            grid[r][c] = 'empty';
33	        }
34	    }
35	    return grid;
36	};
37	
38	GridCanvas.prototype._assertInBounds = function(x, y) {
39	    if (x < 0 || x >= this.cols || y < 0 || y >= this.rows) {
40	        throw new RangeError('(' + x + ', ' + y + ') out of bounds ' +
41	                             this.cols + 'x' + this.rows);
42	    }
43	};
44	
45	GridCanvas.prototype.getCell = function(x, y) {
46	    this._assertInBounds(x, y);
47	    return this._grid[y][x];
48	};
49	
50	GridCanvas.prototype.toggleWall = function(x, y) {
51	    this._assertInBounds(x, y);
52	    var cell = this._grid[y][x];
53	    if (cell === 'start' || cell === 'end') return; // protected
54	    this._grid[y][x] = (cell === 'wall') ? 'empty' : 'wall';
55	};
56	
57	GridCanvas.prototype.setStart = function(x, y) {
58	    this._assertInBounds(x, y);
59	    if (this.end && this.end.x === x && this.end.y === y) {
60	        throw new Error('Cannot place start on end cell');
61	    }
62	    // Clear old start
63	    if (this.start) {
64	        this._grid[this.start.y][this.start.x] = 'empty';
65	    }
66	    this.start = { x: x, y: y };
67	    this._grid[y][x] = 'start';
68	};
69	
70	GridCanvas.prototype.setEnd = function(x, y) {
71	    this._assertInBounds(x, y);
72	    if (this.start && this.start.x === x && this.start.y === y) {
73	        throw new Error('Cannot place end on start cell');
74	    }
75	    // Clear old end
76	    if (this.end) {
77	        this._grid[this.end.y][this.end.x] = 'empty';
78	    }
79	    this.end = { x: x, y: y };
80	    this._grid[y][x] = 'end';
81	};
82	
83	GridCanvas.prototype.isWalkable = function(x, y) {
84	    this._assertInBounds(x, y);
85	    return this._grid[y][x] !== 'wall';
86	};
87	
88	GridCanvas.prototype.clearWalls = function() {
89	    for (var r = 0; r < this.rows; r++) {
90	        for (var c = 0; c < this.cols; c++) {
91	            if (this._grid[r][c] === 'wall') {
92	                this._grid[r][c] = 'empty';
93	            }
94	        }
95	    }
96	};
97	
98	GridCanvas.prototype.reset = function() {
99	    this.start = null;
100	    this.end   = null;
101	    this._grid = this._makeGrid(this.cols, this.rows);
102	};
103	
104	GridCanvas.prototype.getState = function() {
105	    var r, c, walls = [];
106	    var grid = new Array(this.rows);
107	    for (r = 0; r < this.rows; r++) {
108	        grid[r] = new Array(this.cols);
109	        for (c = 0; c < this.cols; c++) {
110	            grid[r][c] = this._grid[r][c];
111	            if (this._grid[r][c] === 'wall') {
112	                walls.push({ x: c, y: r });
113	            }
114	        }
115	    }
116	    return {
117	        grid:  grid,
118	        start: this.start ? { x: this.start.x, y: this.start.y } : null,
119	        end:   this.end   ? { x: this.end.x,   y: this.end.y   } : null,
120	        walls: walls
121	    };
122	};
123	
124	GridCanvas.prototype.setState = function(state) {
125	    this.reset();
126	    var r, c;
127	    for (r = 0; r < this.rows; r++) {
128	        for (c = 0; c < this.cols; c++) {
129	            var type = state.grid[r][c];
130	            if (type === 'wall') {
131	                this._grid[r][c] = 'wall';
132	            }
133	        }
134	    }
135	    if (state.start) this.setStart(state.start.x, state.start.y);
136	    if (state.end)   this.setEnd(state.end.x, state.end.y);
137	};
138	
139	// Node.js export (browser usage via global)
140	if (typeof module !== 'undefined' && module.exports) {
141	    module.exports = GridCanvas;
142	}
