18	}(this, function(PF) {
19	
20	    // ─── Algorithm registry ────────────────────────────────────────────────
21	    var ALGORITHMS = [
22	        { id: 'AStarFinder',           label: 'A*' },
23	        { id: 'BiAStarFinder',         label: 'Bi-directional A*' },
24	        { id: 'BestFirstFinder',       label: 'Best-First' },
25	        { id: 'BiBestFirstFinder',     label: 'Bi-directional Best-First' },
26	        { id: 'BreadthFirstFinder',    label: 'Breadth-First Search' },
27	        { id: 'BiBreadthFirstFinder',  label: 'Bi-directional BFS' },
28	        { id: 'DijkstraFinder',        label: 'Dijkstra' },
29	        { id: 'BiDijkstraFinder',      label: 'Bi-directional Dijkstra' },
30	        { id: 'IDAStarFinder',         label: 'IDA*' },
31	        { id: 'JumpPointFinder',       label: 'Jump Point Search' },
32	    ];
33	
34	    // ─── Speed config (operations per second) ─────────────────────────────
35	    var SPEED_CONFIG = {
36	        min: 10,
37	        default: 200,
38	        max: 1000,
39	    };
40	
41	    // ─── Grid size ─────────────────────────────────────────────────────────
42	    var GRID_SIZE_DEFAULT = { width: 15, height: 15 };
43	    var GRID_SIZE_MIN = 5;
44	    var GRID_SIZE_MAX = 50;
45	
46	    // ─── validateGridSize ──────────────────────────────────────────────────
47	    function validateGridSize(width, height) {
48	        if (!Number.isInteger(width) || !Number.isInteger(height)) return false;
49	        if (width < GRID_SIZE_MIN || height < GRID_SIZE_MIN) return false;
50	        if (width > GRID_SIZE_MAX || height > GRID_SIZE_MAX) return false;
51	        return true;
52	    }
53	
54	    // ─── serializeGrid ─────────────────────────────────────────────────────
55	    /**
56	     * Convert a PF.Grid + start/end positions to a plain object.
57	     * @param {PF.Grid} grid
58	     * @param {number} startX
59	     * @param {number} startY
60	     * @param {number} endX
61	     * @param {number} endY
62	     * @returns {Object}
63	     */
64	    function serializeGrid(grid, startX, startY, endX, endY) {
65	        var walls = [];
66	        for (var y = 0; y < grid.height; y++) {
67	            for (var x = 0; x < grid.width; x++) {
68	                if (!grid.isWalkableAt(x, y)) {
69	                    walls.push([x, y]);
70	                }
71	            }
72	        }
73	        return {
74	            version: '1',
75	            width:   grid.width,
76	            height:  grid.height,
77	            startX:  startX,
78	            startY:  startY,
79	            endX:    endX,
80	            endY:    endY,
81	            walls:   walls,
82	        };
83	    }
84	
85	    // ─── deserializeGrid ───────────────────────────────────────────────────
86	    /**
87	     * Restore a PF.Grid from a serialized scenario object or JSON string.
88	     * @param {Object|string} data
89	     * @returns {{ grid: PF.Grid, startX: number, startY: number, endX: number, endY: number }}
90	     */
91	    function deserializeGrid(data) {
92	        var scenario = (typeof data === 'string') ? JSON.parse(data) : data;
93	
94	        if (!scenario.version) {
