96	        }
97	        if (!scenario.width || !scenario.height ||
98	            scenario.width <= 0 || scenario.height <= 0) {
99	            throw new Error('Invalid scenario: bad dimensions');
100	        }
101	
102	        var grid = new PF.Grid(scenario.width, scenario.height);
103	
104	        (scenario.walls || []).forEach(function(wall) {
105	            grid.setWalkableAt(wall[0], wall[1], false);
106	        });
107	
108	        return {
109	            grid:   grid,
110	            startX: scenario.startX,
111	            startY: scenario.startY,
112	            endX:   scenario.endX,
113	            endY:   scenario.endY,
114	        };
115	    }
116	
117	    // ─── Preset maps ───────────────────────────────────────────────────────
118	    function makeEmptyScenario(w, h, sx, sy, ex, ey) {
119	        return { version: '1', width: w, height: h, startX: sx, startY: sy, endX: ex, endY: ey, walls: [] };
120	    }
121	
122	    var PRESETS = [
123	        {
124	            id: 'empty',
125	            label: 'Empty 15×15',
126	            scenario: makeEmptyScenario(15, 15, 1, 7, 13, 7),
127	        },
128	        {
129	            id: 'corridor',
130	            label: 'Single Corridor',
131	            scenario: (function() {
132	                // Horizontal walls top and bottom, open middle corridor
133	                var walls = [];
134	                for (var x = 0; x < 15; x++) {
135	                    if (x !== 0 && x !== 14) {
136	                        walls.push([x, 3]);
137	                        walls.push([x, 11]);
138	                    }
139	                }
140	                return { version: '1', width: 15, height: 15,
141	                         startX: 1, startY: 7, endX: 13, endY: 7, walls: walls };
142	            }()),
143	        },
144	        {
145	            id: 'maze',
146	            label: 'Simple Maze',
147	            scenario: (function() {
148	                // Alternating horizontal barriers with gaps
149	                var walls = [];
150	                var rows = [2, 4, 6, 8, 10, 12];
151	                rows.forEach(function(row, i) {
152	                    for (var x = 0; x < 14; x++) {
153	                        // Gap on left for even rows, right for odd rows
154	                        var gapX = (i % 2 === 0) ? 13 : 0;
155	                        if (x !== gapX) walls.push([x, row]);
156	                    }
157	                });
158	                return { version: '1', width: 15, height: 15,
159	                         startX: 1, startY: 0, endX: 13, endY: 14, walls: walls };
160	            }()),
161	        },
162	        {
163	            id: 'diagonal_barrier',
164	            label: 'Diagonal Barrier',
165	            scenario: (function() {
166	                var walls = [];
167	                for (var i = 1; i < 14; i++) {
168	                    walls.push([i, i]);
169	                }
170	                return { version: '1', width: 15, height: 15,
171	                         startX: 0, startY: 7, endX: 14, endY: 7, walls: walls };
172	            }()),
173	        },
174	        {
175	            id: 'spiral',
