183	                for (var y2 = 4; y2 < 11; y2++) { walls.push([3, y2]); }
184	                // Inner ring
185	                for (var x3 = 5; x3 < 11; x3++) { walls.push([x3, 4]); }
186	                for (var y3 = 5; y3 < 10; y3++) { walls.push([10, y3]); }
187	                for (var x4 = 5; x4 < 10; x4++) { walls.push([x4, 10]); }
188	                return { version: '1', width: 15, height: 15,
189	                         startX: 0, startY: 0, endX: 7, endY: 7, walls: walls };
190	            }()),
191	        },
192	    ];
193	
194	    return {
195	        ALGORITHMS:         ALGORITHMS,
196	        SPEED_CONFIG:       SPEED_CONFIG,
197	        GRID_SIZE_DEFAULT:  GRID_SIZE_DEFAULT,
198	        GRID_SIZE_MIN:      GRID_SIZE_MIN,
199	        GRID_SIZE_MAX:      GRID_SIZE_MAX,
200	        PRESETS:            PRESETS,
201	        validateGridSize:   validateGridSize,
202	        serializeGrid:      serializeGrid,
203	        deserializeGrid:    deserializeGrid,
204	    };
205	}));
