1	/**
2	 * RunStore — persists pathfinding run records to a storage backend.
3	 *
4	 * Storage must implement: getItem(key), setItem(key, val), removeItem(key).
5	 * Defaults to an in-memory store when none is provided (browser: pass localStorage).
6	 */
7	
8	var STORAGE_KEY = 'pf_runs';
9	
10	function MemStorage() {
11	    this._data = {};
12	}
13	MemStorage.prototype.getItem = function(key) {
14	    return this._data.hasOwnProperty(key) ? this._data[key] : null;
15	};
16	MemStorage.prototype.setItem = function(key, val) {
17	    this._data[key] = String(val);
18	};
19	MemStorage.prototype.removeItem = function(key) {
20	    delete this._data[key];
21	};
22	
23	function RunStore(storage) {
24	    this._storage = storage || new MemStorage();
25	    this._counter = 0;
26	}
27	
28	RunStore.prototype._read = function() {
29	    var raw = this._storage.getItem(STORAGE_KEY);
30	    if (!raw) return [];
31	    try { return JSON.parse(raw); } catch (e) { return []; }
32	};
33	
34	RunStore.prototype._write = function(runs) {
35	    this._storage.setItem(STORAGE_KEY, JSON.stringify(runs));
36	};
37	
38	/**
39	 * Save a run record. Assigns a unique id and returns the stored record.
40	 */
41	RunStore.prototype.saveRun = function(record) {
42	    var runs = this._read();
43	    var id = String(Date.now()) + '_' + (++this._counter);
44	    var saved = {};
45	    for (var k in record) {
46	        if (record.hasOwnProperty(k)) saved[k] = record[k];
47	    }
48	    saved.id = id;
49	    runs.push(saved);
50	    this._write(runs);
51	    return saved;
52	};
53	
54	/**
55	 * Return all saved runs (oldest first).
56	 */
57	RunStore.prototype.loadRuns = function() {
58	    return this._read();
59	};
60	
61	/**
62	 * Return a single run by id, or null if not found.
63	 */
64	RunStore.prototype.getRunById = function(id) {
65	    var runs = this._read();
66	    for (var i = 0; i < runs.length; i++) {
67	        if (runs[i].id === id) return runs[i];
68	    }
69	    return null;
70	};
71	
72	/**
73	 * Delete a single run by id. No-op if id not found.
74	 */
75	RunStore.prototype.deleteRun = function(id) {
76	    var runs = this._read();
77	    var filtered = runs.filter(function(r) { return r.id !== id; });
78	    this._write(filtered);
79	};
80	
81	/**
82	 * Remove all saved runs.
83	 */
84	RunStore.prototype.clearRuns = function() {
85	    this._storage.removeItem(STORAGE_KEY);
86	};
87	
88	module.exports = RunStore;
