11	        },
12	        blocked: {
13	            fill: 'grey',
14	            'stroke-opacity': 0.2,
15	        },
16	        start: {
17	            fill: '#0d0',
18	            'stroke-opacity': 0.2,
19	        },
20	        end: {
21	            fill: '#e40',
22	            'stroke-opacity': 0.2,
23	        },
24	        opened: {
25	            fill: '#98fb98',
26	            'stroke-opacity': 0.2,
27	        },
28	        closed: {
29	            fill: '#afeeee',
30	            'stroke-opacity': 0.2,
31	        },
32	        failed: {
33	            fill: '#ff8888',
34	            'stroke-opacity': 0.2,
35	        },
