60	    /**
61	     * Generate the grid asynchronously.
62	     * This method will be a very expensive task.
63	     * Therefore, in order to not to block the rendering of browser ui,
64	     * I decomposed the task into smaller ones. Each will only generate a row.
65	     */
66	    generateGrid: function(callback) {
67	        var i, j, x, y,
68	            rect,
69	            normalStyle, nodeSize,
70	            createRowTask, sleep, tasks,
71	            nodeSize    = this.nodeSize,
72	            normalStyle = this.nodeStyle.normal,
73	            numCols     = this.numCols,
74	            numRows     = this.numRows,
75	            paper       = this.paper,
76	            rects       = this.rects = [],
