78	
79	        paper.setSize(numCols * nodeSize, numRows * nodeSize);
80	
81	        createRowTask = function(rowId) {
82	            return function(done) {
83	                rects[rowId] = [];
84	                for (j = 0; j < numCols; ++j) {
85	                    x = j * nodeSize;
86	                    y = rowId * nodeSize;
87	
88	                    rect = paper.rect(x, y, nodeSize, nodeSize);
89	                    rect.attr(normalStyle);
90	                    rects[rowId].push(rect);
91	                }
92	                $stats.text(
93	                    'generating grid ' +
94	                    Math.round((rowId + 1) / numRows * 100) + '%'
95	                );
96	                done(null);
97	            };
98	        };
99	
100	        sleep = function(done) {
101	            setTimeout(function() {
102	                done(null);
103	            }, 0);
104	        };
105	
106	        tasks = [];
107	        for (i = 0; i < numRows; ++i) {
108	            tasks.push(createRowTask(i));
109	            tasks.push(sleep);
110	        }
