293	            'time: ' + opts.timeSpent + 'ms',
294	            'operations: ' + opts.operationCount
295	        ];
296	        $('#stats').show().html(texts.join('<br>'));
297	    },
298	    setCoordDirty: function(gridX, gridY, isDirty) {
299	        var x, y,
300	            numRows = this.numRows,
301	            numCols = this.numCols,
302	            coordDirty;
303	
304	        if (this.coordDirty === undefined) {
305	            coordDirty = this.coordDirty = [];
306	            for (y = 0; y < numRows; ++y) {
307	                coordDirty.push([]);
308	                for (x = 0; x < numCols; ++x) {
