321	            coords = [];
322	
323	        if (coordDirty === undefined) {
324	            return [];
325	        }
326	
327	        for (y = 0; y < numRows; ++y) {
328	            for (x = 0; x < numCols; ++x) {
329	                if (coordDirty[y][x]) {
330	                    coords.push([x, y]);
331	                }
332	            }
333	        }
334	        return coords;
335	    },
336	};
