343	            },
344	        };
345	
346	        this.operations = [];
347	    },
348	    bindEvents: function() {
349	        $('#draw_area').mousedown($.proxy(this.mousedown, this));
350	        $(window)
351	            .mousemove($.proxy(this.mousemove, this))
352	            .mouseup($.proxy(this.mouseup, this));
353	    },
354	    loop: function() {
355	        var interval = 1000 / this.operationsPerSecond;
356	        (function loop() {
357	            if (!Controller.is('searching')) {
358	                return;
359	            }
360	            Controller.step();
361	            setTimeout(loop, interval);
362	        })();
363	    },
364	    step: function() {
365	        var operations = this.operations,
366	            op, isSupported;
367	
368	        do {
369	            if (!operations.length) {
370	                this.finish(); // transit to `finished` state
371	                return;
372	            }
373	            op = operations.shift();
374	            isSupported = View.supportedOperations.indexOf(op.attr) !== -1;
375	        } while (!isSupported);
376	
377	        View.setAttributeAt(op.x, op.y, op.attr, op.value);
378	    },
379	    clearOperations: function() {
380	        this.operations = [];
381	    },
382	    clearFootprints: function() {
383	        View.clearFootprints();
384	        View.clearPath();
385	    },
386	    clearAll: function() {
387	        this.clearFootprints();
388	        View.clearBlockedNodes();
389	    },
390	    buildNewGrid: function() {
391	        this.grid = new PF.Grid(this.gridSize[0], this.gridSize[1]);
392	    },
393	    mousedown: function (event) {
394	        var coord = View.toGridCoordinate(event.pageX, event.pageY),
395	            gridX = coord[0],
396	            gridY = coord[1],
397	            grid  = this.grid;
398	
399	        if (this.can('dragStart') && this.isStartPos(gridX, gridY)) {
400	            this.dragStart();
401	            return;
402	        }
403	        if (this.can('dragEnd') && this.isEndPos(gridX, gridY)) {
404	            this.dragEnd();
405	            return;
406	        }
407	        if (this.can('drawWall') && grid.isWalkableAt(gridX, gridY)) {
408	            this.drawWall(gridX, gridY);
409	            return;
410	        }
411	        if (this.can('eraseWall') && !grid.isWalkableAt(gridX, gridY)) {
412	            this.eraseWall(gridX, gridY);
413	        }
414	    },
415	    mousemove: function(event) {
416	        var coord = View.toGridCoordinate(event.pageX, event.pageY),
417	            grid = this.grid,
418	            gridX = coord[0],
419	            gridY = coord[1];
420	
421	        if (this.isStartOrEndPos(gridX, gridY)) {
422	            return;
423	        }
424	
425	        switch (this.current) {
426	        case 'draggingStart':
427	            if (grid.isWalkableAt(gridX, gridY)) {
428	                this.setStartPos(gridX, gridY);
429	            }
430	            break;
431	        case 'draggingEnd':
432	            if (grid.isWalkableAt(gridX, gridY)) {
433	                this.setEndPos(gridX, gridY);
434	            }
435	            break;
436	        case 'drawingWall':
437	            this.setWalkableAt(gridX, gridY, false);
438	            break;
439	        case 'erasingWall':
440	            this.setWalkableAt(gridX, gridY, true);
441	            break;
442	        }
443	    },
444	    mouseup: function(event) {
445	        if (Controller.can('rest')) {
446	            Controller.rest();
447	        }
448	    },
449	    setButtonStates: function() {
450	        $.each(arguments, function(i, opt) {
451	            var $button = Controller.$buttons.eq(opt.id - 1);
452	            if (opt.text) {
453	                $button.text(opt.text);
454	            }
455	            if (opt.callback) {
456	                $button
457	                    .unbind('click')
458	                    .click(opt.callback);
459	            }
460	            if (opt.enabled === undefined) {
461	                return;
462	            } else if (opt.enabled) {
463	                $button.removeAttr('disabled');
464	            } else {
465	                $button.attr({ disabled: 'disabled' });
466	            }
467	        });
468	    },
469	    /**
470	     * When initializing, this method will be called to set the positions
471	     * of start node and end node.
472	     * It will detect user's display size, and compute the best positions.
473	     */
474	    setDefaultStartEndPos: function() {
475	        var width, height,
476	            marginRight, availWidth,
477	            centerX, centerY,
478	            endX, endY,
479	            nodeSize = View.nodeSize;
480	
481	        width  = $(window).width();
482	        height = $(window).height();
483	
484	        marginRight = $('#algorithm_panel').width();
485	        availWidth = width - marginRight;
486	
487	        centerX = Math.ceil(availWidth / 2 / nodeSize);
488	        centerY = Math.floor(height / 2 / nodeSize);
489	
490	        this.setStartPos(centerX - 5, centerY);
491	        this.setEndPos(centerX + 5, centerY);
492	    },
493	    setStartPos: function(gridX, gridY) {
494	        this.startX = gridX;
495	        this.startY = gridY;
496	        View.setStartPos(gridX, gridY);
497	    },
498	    setEndPos: function(gridX, gridY) {
499	        this.endX = gridX;
500	        this.endY = gridY;
501	        View.setEndPos(gridX, gridY);
502	    },
503	    setWalkableAt: function(gridX, gridY, walkable) {
504	        this.grid.setWalkableAt(gridX, gridY, walkable);
505	        View.setAttributeAt(gridX, gridY, 'walkable', walkable);
506	    },
507	    isStartPos: function(gridX, gridY) {
508	        return gridX === this.startX && gridY === this.startY;
509	    },
510	    isEndPos: function(gridX, gridY) {
511	        return gridX === this.endX && gridY === this.endY;
512	    },
513	    isStartOrEndPos: function(gridX, gridY) {
514	        return this.isStartPos(gridX, gridY) || this.isEndPos(gridX, gridY);
515	    },
516	});
