    var algoId  = $('#algo_select').val();
    var finder  = buildFinder(algoId);
    if (!finder) { setStatus('Unknown algorithm: ' + algoId); return; }

    var cloned  = grid.clone();
    var t0      = performance.now ? performance.now() : Date.now();
    var path    = finder.findPath(startX, startY, endX, endY, cloned);
    var timeMs  = (performance.now ? performance.now() : Date.now()) - t0;
    var opsCopy = operations.slice();
    operations  = [];

    // Count unique nodes explored (opened or closed)
    var exploredSet = {};
    opsCopy.forEach(function(op) {
        if (op.attr === 'opened' || op.attr === 'closed') {
            exploredSet[op.x + ',' + op.y] = true;
        }
    });
    var nodesExplored = Object.keys(exploredSet).length;

    isSearching = true;
    setStatus('Searching…');

    var opIdx = 0;
    animTimer = setInterval(function() {
        if (opIdx >= opsCopy.length) {
            clearInterval(animTimer);
            isSearching = false;
            View.drawPath(path);
            if (path.length) {
                setStatus('Path found · ' + path.length + ' nodes');
            } else {
                setStatus('No path found');
            }
            // Show score card
            var algoLabel = (function() {
                var sel = $('#algo_select option:selected');
                return sel.length ? sel.text() : algoId;
            }());
            var record = Scorer.captureRun(algoLabel, path, timeMs, nodesExplored);
            Scorer.showScoreCard(record);
            return;
        }
        var op = opsCopy[opIdx++];
        if (View.supportedOperations.indexOf(op.attr) !== -1) {
            View.setAttributeAt(op.x, op.y, op.attr, op.value);
        }
    }, 1000 / opsPerSecond);
}

function abortSearch() {
    if (animTimer) { clearInterval(animTimer); animTimer = null; }
    isSearching = false;
}

function buildFinder(id) {
    switch (id) {
        case 'AStarFinder':          return new PF.AStarFinder();
        case 'BiAStarFinder':        return new PF.BiAStarFinder();
        case 'BestFirstFinder':      return new PF.BestFirstFinder();
        case 'BiBestFirstFinder':    return new PF.BiBestFirstFinder();
        case 'BreadthFirstFinder':   return new PF.BreadthFirstFinder();
        case 'BiBreadthFirstFinder': return new PF.BiBreadthFirstFinder();
        case 'DijkstraFinder':       return new PF.DijkstraFinder();
        case 'BiDijkstraFinder':     return new PF.BiDijkstraFinder();
        case 'IDAStarFinder':        return new PF.IDAStarFinder({ timeLimit: 10 });
        case 'JumpPointFinder':      return new PF.JumpPointFinder({
            diagonalMovement: PF.DiagonalMovement.IfAtMostOneObstacle
        });
        default: return null;
    }
}

// ── Clear ─────────────────────────────────────────────────────────────
function clearGrid() {
    if (!grid) return;
    abortSearch();
    var w = grid.width, h = grid.height;
    initGrid(w, h, startX, startY, endX, endY);
    setStatus('Grid cleared');
}

// ── Resize ────────────────────────────────────────────────────────────
function resizeGrid() {
    var w = parseInt($('#grid_width').val());
    var h = parseInt($('#grid_height').val());
    if (!SC.validateGridSize(w, h)) {
        setStatus('Invalid size: must be 5–50.');
        return;
    }
    initGrid(w, h);
}

// ── Preset load ───────────────────────────────────────────────────────
$('#preset_select').on('change', function() {
    var id = this.value;
    if (!id) return;
    var preset = SC.PRESETS.filter(function(p) { return p.id === id; })[0];
    if (!preset) return;
    loadScenario(preset.scenario);
